var building_info = '0Aq5Q1g5WagVodFRGNlFkYWx2Yy1BRHd6QWlWTWtxRHc';
var email = Session.getUser().getUserLoginId();
var buildingstab = 'BuildingInfo';
var misc ='Misc';

function doGet() {
 var app = UiApp.createApplication();

    var BuildingSheet = SpreadsheetApp.openById(building_info).getSheetByName(buildingstab);
    var buildingData = BuildingSheet.getDataRange().getValues();  
    var miscSheet = SpreadsheetApp.openById(building_info).getSheetByName(misc);
    var miscData = miscSheet.getDataRange().getValues();
    var RequestDB = miscData[3][1];
    var approvetab = miscData[5][1];
    var denytab = miscData[6][1];
    var RequestTab = miscData[4][1];
    var hrSecEmail = miscData[1][1];
    var superEmail = miscData[2][1];
    var ss = SpreadsheetApp.openById(RequestDB).getSheetByName(RequestTab);
    var requestData = ss.getDataRange().getValues();
    var ss2 = SpreadsheetApp.openById(RequestDB).getSheetByName(approvetab);
    var approveData = ss2.getDataRange().getValues();
    var ss3 = SpreadsheetApp.openById(RequestDB).getSheetByName(denytab);
    var denyData = ss3.getDataRange().getValues();
    var title = email + ' Leave Requests - ' + Utilities.formatDate(new Date(), "GMT-05:00", "E MM/dd/yyyy");
    var counter = 0;
    var i = 0;
    var permission = false;
    //var values;
    var range;

  if (email != hrSecEmail && email != superEmail) {
      for (var cnt = 1; cnt < buildingData.length; cnt++) {
        for (var cnt2 = 1; cnt2 < 6; cnt2++) {
         if (email == buildingData[cnt][cnt2])
             permission = true;
         }
      }//end for
      }//end if not super of hr
      else 
      permission = true;

  if (permission) {   

    var ssNew = SpreadsheetApp.create(title);
    var url = ssNew.getUrl();

    if (email != hrSecEmail && email != superEmail) {// not super or secretary to super
    ssNew.getActiveSheet().setName('Open Requests');
    ssNew.getActiveSheet();  
    ssNew.insertSheet('Approved');
    ssNew.insertSheet('Denied');
    var key = url.split('=');

    var first = 1;
    //create the write method to the sheets  
    //var ssc = SpreadsheetApp.openById(key[1]).getSheetByName('Open Requests'); 
    //var ssc1 = SpreadsheetApp.openById(key[1]).getSheetByName('Approved');
    //var ssc2 = SpreadsheetApp.openById(key[1]).getSheetByName('Denied');
  for (var i = 0; i < 3; i++)
  {
    if (i == 0) {
      var ssc = SpreadsheetApp.openById(key[1]).getSheetByName('Open Requests');
      first = 1;
    }
    else if (i == 1) {
      var ssc = SpreadsheetApp.openById(key[1]).getSheetByName('Approved');
      requestData = ss2.getDataRange().getValues();
      first = 1;
    }
    else if (i == 2) {
      var ssc = SpreadsheetApp.openById(key[1]).getSheetByName('Denied');
      requestData = ss3.getDataRange().getValues();
      first = 1;
    }

    var counter2 = 2;

    while(counter2 < buildingData.length) {

      counter = 0;

      if (buildingData[counter2][2] == email || buildingData[counter2][1] == email ) {
        while(requestData.length != counter) {
          if (requestData[counter][4] == buildingData[counter2][0] || first ==1) {
            if (first == 1)
              first++;

            var values = [[requestData[counter][0], requestData[counter][1], 
                requestData[counter][2], requestData[counter][3], 
                requestData[counter][4], requestData[counter][5], 
                requestData[counter][6], requestData[counter][7], 
                requestData[counter][8], requestData[counter][9], 
                requestData[counter][10], requestData[counter][11], 
                requestData[counter][12], requestData[counter][13], 
                requestData[counter][14], requestData[counter][15], 
                requestData[counter][16], requestData[counter][17],
                requestData[counter][18], requestData[counter][19],
                requestData[counter][20], requestData[counter][21],
                requestData[counter][22], requestData[counter][23],]];

                          range = ssc.getRange(ssc.getLastRow()+1, 1, 1, 24);
                          range.setValues(values);

            }//end if

          counter++;
        }//end while 
      }
      else if (buildingData[counter2][4] == email || buildingData[counter2][3] == email) {
         while(requestData.length != counter) {
          if (requestData[counter][4] == buildingData[counter2][0] && requestData[counter][5] == 'Yes' || first ==1) {
            if (first == 1)
              first++;            

              var values = [[requestData[counter][0], requestData[counter][1], 
                requestData[counter][2], requestData[counter][3], 
                requestData[counter][4], requestData[counter][5], 
                requestData[counter][6], requestData[counter][7], 
                requestData[counter][8], requestData[counter][9], 
                requestData[counter][10], requestData[counter][11], 
                requestData[counter][12], requestData[counter][13], 
                requestData[counter][14], requestData[counter][15], 
                requestData[counter][16], requestData[counter][17],
                requestData[counter][18], requestData[counter][19],
                requestData[counter][20], requestData[counter][21],
                requestData[counter][22], requestData[counter][23],]];

                          range = ssc.getRange(ssc.getLastRow()+1, 1, 1, 24);
                          range.setValues(values);
            }//end if
          counter++;
        }//end while
   }

    counter2++;
    }     
    }
    }
    else { //is super or super secretary
     ss.copyTo(ssNew).setName('Open Requests');
     ss2.copyTo(ssNew).setName('Approved');
     ss3.copyTo(ssNew).setName('Denied');      
    }

  ssNew.addEditor(email);                          
  app.add(app.createLabel('Your spreadsheet has been created and is now in your Google Drive. It is called ' + title));
  app.add(app.createAnchor("Click here to see your detailed leave information.", url).setTarget('_self')); 
  }//end if permission
  else {
    app.add(app.createLabel('You do not have permission to export this information.'));
    return app;
  }//end else ! permission
  return app;
}// end doGet
